class OriginModel(OriginPreTrainedTitansModel):
    def __init__(self, config: OriginConfig):
        super().__init__(config)

        self.padding_idx = config.pad_token_id
        self.vocab_size = config.vocab_size
        self.chunk_size = config.chunk_size

        self.embed_tokens = nn.Embedding(
            config.vocab_size, config.hidden_size, self.padding_idx
        )
        self.layers = nn.ModuleList(
            [
                OriginLayer(config, layer_idx)
                for layer_idx in range(config.num_hidden_layers)
            ]
        )
        self.norm = TitansRMSNorm(config.hidden_size, eps=config.rms_norm_eps)
        self.rotary_emb = TitansRotaryEmbedding(config=config)
        self.gradient_checkpointing = False
        self.validate_config()

        # Initialize weights and apply final processing
        self.post_init()

    def get_input_embeddings(self):
        return self.embed_tokens

    def set_input_embeddings(self, value):
        self.embed_tokens = value

    @can_return_tuple
    @auto_docstring
    def forward(
        self,
        input_ids: Optional[torch.LongTensor] = None,
        position_ids: Optional[torch.LongTensor] = None,
        cache_params: Optional[OriginCache] = None,
        mini_batch_size: Optional[int] = None,
        inputs_embeds: Optional[torch.FloatTensor] = None,
        use_cache: Optional[bool] = None,
        output_hidden_states: Optional[bool] = None,
        return_dict: Optional[bool] = None,
        **kwargs: Unpack[TransformersKwargs],
    ) -> Union[tuple, OriginOutput]:
        """
        Forward pass through the TTT Linear model.

        Args:
            input_ids (`torch.LongTensor` of shape `(batch_size, sequence_length)`, *optional*):
                Indices of input sequence tokens in the vocabulary.
            position_ids (`torch.LongTensor` of shape `(batch_size, sequence_length)`, *optional*):
                Indices of positions of each input sequence token in the position embeddings.
            cache_params (`OriginCache`, *optional*):
                Cache object for storing fast weights and states during incremental generation.
                Contains the evolving learning state of the model for efficient inference.
            mini_batch_size (`int`, *optional*):
                Size of mini-batches for TTT adaptation. If None, uses config.chunk_size.
                Controls the granularity of test-time learning updates.
            inputs_embeds (`torch.FloatTensor` of shape `(batch_size, sequence_length, hidden_size)`, *optional*):
                Optionally, instead of passing `input_ids` you can choose to directly pass an embedded representation.
            use_cache (`bool`, *optional*):
                If set to `True`, cache_params is returned and can be used to speed up decoding.
            output_hidden_states (`bool`, *optional*):
                Whether or not to return the hidden states of all layers.
            return_dict (`bool`, *optional*):
                Whether or not to return a ModelOutput instead of a plain tuple.

        Returns:
            `Union[Tuple, OriginOutput]`:
                Either a tuple of tensors or OriginOutput containing:
                - last_hidden_state: The sequence of hidden-states at the output of the last layer
                - cache_params: The updated cache containing fast weights and states
                - hidden_states: Hidden-states of all layers (if output_hidden_states=True)
        """
        output_hidden_states = (
            output_hidden_states
            if output_hidden_states is not None
            else self.config.output_hidden_states
        )
        use_cache = use_cache if use_cache is not None else self.config.use_cache
        return_dict = (
            return_dict if return_dict is not None else self.config.use_return_dict
        )

        if (input_ids is None) ^ (inputs_embeds is not None):
            raise ValueError(
                "You cannot specify both input_ids and inputs_embeds at the same time, and must specify either one"
            )

        if "attention_mask" in kwargs:
            logger.warning_once(
                f"{self.__class__.__name__} does not use attention mask, but it is provided. It will be ignored."
            )
            kwargs.pop("attention_mask")  # Origin does not use attention mask

        if inputs_embeds is None:
            inputs_embeds = self.embed_tokens(input_ids)

        if mini_batch_size is None:  # Batch Learning Process
            mini_batch_size = self.chunk_size
        elif mini_batch_size > self.chunk_size:
            raise ValueError(
                "Mini-batch size cannot be greater than model chunk size configuration"
            )

        rope_start_pos = 0
        if cache_params is None and use_cache:
            cache_params = OriginCache(
                self.config, inputs_embeds.size(0), self.layers, self.device
            )
            rope_start_pos = cache_params.token_len

        if position_ids is None:
            position_ids = torch.arange(
                rope_start_pos,
                rope_start_pos + inputs_embeds.shape[1],
                dtype=torch.long,
                device=inputs_embeds.device,
            ).unsqueeze(0)

        hidden_states = inputs_embeds

        pad_length = 0
        if mini_batch_size != self.chunk_size:  # Online Adaptation Mode (do not pad)
            if hidden_states.shape[1] != mini_batch_size:
                raise ValueError(
                    "Input token count does not match to the online mini-batch size."
                )
        elif hidden_states.shape[1] % mini_batch_size > 0:  # Padding for batch process
            pad_length = mini_batch_size - (hidden_states.shape[1] % mini_batch_size)
            hidden_states = F.pad(hidden_states, (0, 0, 0, pad_length))
            position_ids = F.pad(position_ids, (0, pad_length))

        position_embeddings = self.rotary_emb(input_ids, position_ids)

        all_hidden_states = () if output_hidden_states else None

        for layer in self.layers:
            if self.gradient_checkpointing and self.training:
                hidden_states = self._gradient_checkpointing_func(
                    layer.__call__,
                    hidden_states,
                    position_embeddings,
                    position_ids,
                    cache_params,
                    mini_batch_size,
                    **kwargs,
                )
            else:
                hidden_states = layer(
                    hidden_states,
                    position_embeddings,
                    position_ids=position_ids,
                    cache_params=cache_params,
                    mini_batch_size=mini_batch_size,
                    **kwargs,
                )

            if output_hidden_states:
                if pad_length > 0:
                    all_hidden_states = (
                        all_hidden_states + (hidden_states[:, :-pad_length])
                    )
                else:
                    all_hidden_states = all_hidden_states + (hidden_states,)

        if pad_length > 0:
            hidden_states = hidden_states[:, :-pad_length]
        hidden_states = self.norm(hidden_states)

        if use_cache:
            cache_params.token_len += hidden_states.shape[1]

        if not return_dict:
            return tuple(
                v
                for v in [hidden_states, cache_params, all_hidden_states]
                if v is not None
            )

        return OriginOutput(
            last_hidden_state=hidden_states,
            hidden_states=all_hidden_states,
            cache_params=cache_params if use_cache else None,
        )

    def validate_config(self):
        config = self.config

        # Config validation
        if isinstance(config.adapt_base_lr, tuple) or isinstance(
            config.adapt_base_lr, list
        ):
            if len(config.adapt_base_lr) != config.num_hidden_layers:
                raise ValueError(
                    "adapt_base_lr must be a single value or a list of length num_hidden_layers"
                )
        else:
            config.adapt_base_lr = [config.adapt_base_lr] * config.num_hidden_layers

        if isinstance(config.adapt_base_momentum, tuple) or isinstance(
            config.adapt_base_momentum, list
        ):
            if len(config.adapt_base_momentum) != config.num_hidden_layers:
                raise ValueError(
                    "adapt_base_momentum must be a single value or a list of length num_hidden_layers"
                )
        else:
            config.adapt_base_momentum = [
                config.adapt_base_momentum
            ] * config.num_hidden_layers

        if isinstance(config.adapt_base_weight_decay, tuple) or isinstance(
            config.adapt_base_weight_decay, list
        ):
            if len(config.adapt_base_weight_decay) != config.num_hidden_layers:
                raise ValueError(
                    "adapt_base_weight_decay must be a single value or a list of length num_hidden_layers"
                )
        else:
            config.adapt_base_weight_decay = [
                config.adapt_base_weight_decay
            ] * config.num_hidden_layers


class OriginVariantModel(OriginModel):
    supports_gradient_checkpointing = True
    _no_split_modules = ["OriginMemoryLayer", "OriginCoreLayer"]

    def validate_config(self):
        super().validate_config()
        config = self.config

        # Config split
        memory_config, core_config = copy.copy(config), copy.copy(config)
        if isinstance(config.intermediate_size, tuple) or isinstance(
            config.intermediate_size, list
        ):
            memory_config.intermediate_size, core_config.intermediate_size = (
                config.intermediate_size
            )
        if isinstance(config.num_hidden_layers, tuple) or isinstance(
            config.num_hidden_layers, list
        ):
            memory_config.num_hidden_layers, core_config.num_hidden_layers = (
                config.num_hidden_layers
            )
        if isinstance(config.num_attention_heads, tuple) or isinstance(
            config.num_attention_heads, list
        ):
            memory_config.num_attention_heads, core_config.num_attention_heads = (
                config.num_attention_heads
            )
        if isinstance(config.hidden_act, tuple) or isinstance(config.hidden_act, list):
            memory_config.hidden_act, core_config.hidden_act = config.hidden_act
            core_config.hidden_activation = core_config.hidden_act

        return memory_config, core_config

    def __init__(self, config: OriginConfig):
        super().__init__(config)
        memory_config, core_config = self.validate_config()

        self.padding_idx = config.pad_token_id
        self.vocab_size = config.vocab_size
        self.chunk_size = config.chunk_size

        self.embed_tokens = nn.Embedding(
            config.vocab_size, config.hidden_size, self.padding_idx
        )

        self.fixed_memories = nn.Parameter(
            torch.zeros([config.fixed_memory_size, config.hidden_size])
        )
        self.memories = nn.ModuleList(
            [
                OriginMemoryLayer(memory_config, layer_idx)
                for layer_idx in range(config.num_hidden_layers)
            ]
        )
        self.cores = nn.ModuleList(
            [
                OriginCoreLayer(core_config, layer_idx)
                for layer_idx in range(config.num_hidden_layers)
            ]
        )

        self.norm = TitansRMSNorm(config.hidden_size, eps=config.rms_norm_eps)
        self.rotary_emb = TitansRotaryEmbedding(config=config)
        self.gradient_checkpointing = False

        # Initialize weights and apply final processing
        self.post_init()

    @property
    def layers(self):
        return self.memories + self.cores


class OriginMACModel(OriginModel):
    base_model_prefix = "titans_origin_mac"


class OriginMAEModel(OriginModel):
    base_model_prefix = "titans_origin_mae"

    @property
    def layers(self):
        for layer in self.memories:
            yield layer
        for layer in self.cores:
            yield layer


